var d = $input.first().json;

if (!d.userMessage || d.userMessage.trim() === '') {
  throw new Error('Missing required field: message');
}

// ── In-memory session store ──────────────────────────
// In production replace with Redis GET/SET or Postgres query
// For n8n: use a static variable trick or pass history in the request body
var history = [];
try {
  // Accept history from the client payload for stateless setups
  var bodyHistory = $input.first().json.body && $input.first().json.body.history
    ? $input.first().json.body.history : [];
  if (Array.isArray(bodyHistory) && bodyHistory.length > 0) {
    history = bodyHistory;
  }
} catch(e) { history = []; }

// Keep last 10 turns (20 messages) to stay within context window
history = history.slice(-20);

// ── Intent detection ─────────────────────────────────
var msg = (d.userMessage || '').toLowerCase();

var intent = 'general';
if (/refund|broken|damaged|not working|issue|bug|error|complaint|wrong|missing|problem/.test(msg)) {
  intent = 'support';
} else if (/price|pricing|plan|buy|purchase|cost|discount|trial|demo|upgrade|subscribe/.test(msg)) {
  intent = 'sales';
} else if (/human|agent|manager|escalate|speak to someone|real person|help me now/.test(msg)) {
  intent = 'escalate';
}

// ── System prompts per intent ────────────────────────
var systemPrompts = {
  support: (
    'You are a helpful and empathetic customer support agent. '
    + 'Your goal is to resolve the customer\'s issue efficiently. '
    + 'If you cannot resolve it, acknowledge the problem clearly and offer to escalate. '
    + 'Be concise — max 3 short paragraphs. Always end with a follow-up question or clear next step.'
  ),
  sales: (
    'You are a knowledgeable and friendly sales assistant. '
    + 'Help the customer understand the product value and guide them toward the right plan. '
    + 'Do not pressure. Highlight benefits. Offer a free trial or demo when appropriate. '
    + 'Keep replies under 150 words.'
  ),
  escalate: (
    'You are a support agent handling an escalation request. '
    + 'Acknowledge the customer\'s frustration with empathy. '
    + 'Confirm that a human agent will contact them within 2 hours. '
    + 'Collect their preferred contact method if not already provided. '
    + 'Be warm and reassuring.'
  ),
  general: (
    'You are a helpful, friendly AI assistant. '
    + 'Answer questions clearly and concisely. '
    + 'If a question is outside your knowledge, say so honestly and suggest where they might find help. '
    + 'Keep responses under 200 words.'
  )
};

var systemPrompt = systemPrompts[intent] || systemPrompts['general'];

// ── Build messages array for Llama ──────────────────
var messages = [{ role: 'system', content: systemPrompt }];

// Add conversation history
history.forEach(function(turn) {
  messages.push(turn);
});

// Add current user message
messages.push({ role: 'user', content: d.userMessage });

// ── Build request payload ────────────────────────────
// Compatible with Ollama /api/chat, Groq, and Together AI
var isOllama = (d.LLAMA_ENDPOINT || '').includes('localhost') || (d.LLAMA_ENDPOINT || '').includes('11434');

var requestPayload = {
  model:       d.LLAMA_MODEL || 'llama3.1:8b',
  messages:    messages,
  temperature: d.TEMPERATURE || 0.7,
  max_tokens:  d.MAX_TOKENS  || 800,
  stream:      false
};

// Ollama uses slightly different field name
if (isOllama) {
  requestPayload.options = { temperature: d.TEMPERATURE || 0.7, num_predict: d.MAX_TOKENS || 800 };
  delete requestPayload.temperature;
  delete requestPayload.max_tokens;
}

var apiPath = isOllama ? '/api/chat' : '/chat/completions';

return [{ json: {
  sessionId:      d.sessionId,
  userId:         d.userId,
  userName:       d.userName,
  userMessage:    d.userMessage,
  messageId:      d.messageId,
  turnNumber:     d.turnNumber,
  botPersona:     d.botPersona,
  intent:         intent,
  isEscalation:   intent === 'escalate',
  history:        history,
  messages:       messages,
  systemPrompt:   systemPrompt,
  requestPayload: JSON.stringify(requestPayload),
  apiPath:        apiPath,
  isOllama:       isOllama,
  LLAMA_ENDPOINT: d.LLAMA_ENDPOINT,
  LLAMA_API_KEY:  d.LLAMA_API_KEY,
  LLAMA_MODEL:    d.LLAMA_MODEL,
  SLACK_WEBHOOK:  d.SLACK_WEBHOOK,
  SHEET_ID:       d.SHEET_ID,
  startedAt:      new Date().toISOString()
}}];

var raw  = $('Call Llama Model').first().json;
var meta = $('Load Memory and Build Request').first().json;

// ── Extract assistant reply ──────────────────────────
var reply = '';
try {
  // Ollama format
  if (raw.message && raw.message.content) {
    reply = raw.message.content.trim();
  }
  // OpenAI-compatible format (Groq, Together)
  else if (raw.choices && raw.choices.length > 0) {
    reply = (raw.choices[0].message && raw.choices[0].message.content)
      ? raw.choices[0].message.content.trim()
      : (raw.choices[0].text || '').trim();
  }
  // Fallback
  else {
    reply = JSON.stringify(raw);
  }
} catch(e) {
  reply = 'Sorry, I encountered an error. Please try again.';
}

// ── Update session history ──────────────────────────
var updatedHistory = (meta.history || []).slice();
updatedHistory.push({ role: 'user',      content: meta.userMessage });
updatedHistory.push({ role: 'assistant', content: reply });
// Keep last 20 messages
updatedHistory = updatedHistory.slice(-20);

// ── Escalation detection ────────────────────────────
var escalationPhrases = ['escalate', 'human agent', 'speak to someone', 'real person', 'supervisor'];
var userWantsEscalation = meta.isEscalation || false;
var botFlaggedEscalation = /i.ll connect you|escalating|human agent will|contact you within/i.test(reply);
var needsEscalation = userWantsEscalation || botFlaggedEscalation;

// ── Token usage ─────────────────────────────────────
var tokensUsed = 0;
try {
  tokensUsed = raw.usage
    ? (raw.usage.total_tokens || raw.usage.completion_tokens || 0)
    : (raw.eval_count || 0);
} catch(e) {}

return [{ json: {
  sessionId:       meta.sessionId,
  userId:          meta.userId,
  userName:        meta.userName,
  messageId:       meta.messageId,
  turnNumber:      meta.turnNumber,
  intent:          meta.intent,
  userMessage:     meta.userMessage,
  assistantReply:  reply,
  replyLength:     reply.length,
  needsEscalation: needsEscalation,
  updatedHistory:  updatedHistory,
  turnCount:       updatedHistory.length / 2,
  tokensUsed:      tokensUsed,
  model:           meta.LLAMA_MODEL,
  SLACK_WEBHOOK:   meta.SLACK_WEBHOOK,
  SHEET_ID:        meta.SHEET_ID,
  startedAt:       meta.startedAt,
  completedAt:     new Date().toISOString()
}}];
